Here's how to test `DataFetcher` with proper timeout and cancellation handling in MSTest 3.x+:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(2000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = CancellationTokenSource.CreateLinkedTokenSource(
            _testContext.CancellationToken);

        // Act & Assert
        cts.CancelAfter(TimeSpan.FromMilliseconds(100));
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Reusable fake handler
    private sealed class FakeHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public FakeHttpMessageHandler(
            string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content),
            };
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `[Timeout(N)]` + `_testContext.CancellationToken` | Cooperative timeout — test is cancelled cleanly if it hangs |
| `CreateLinkedTokenSource` | Links your explicit cancellation to the test's timeout token, so either can stop the test |
| `Assert.ThrowsExactlyAsync<T>` | Modern replacement for `[ExpectedException]` — lets you inspect the exception |
| `sealed` class + `FakeHttpMessageHandler` | Avoids mocking libraries; gives full control over delay/status |

The cancellation test simulates a slow server (30s delay), cancels after 100ms, and verifies `TaskCanceledException` is thrown — all while respecting the test-level `[Timeout]` as a safety net.
